      [{title:'Middleware для логирования',description:'Пример middleware для мониторинга LLM-запросов.',code:`async function llmWithMonitoring(prompt: string) {\n  const start = Date.now();\n  try {\n    const response = await openai.chat.completions.create({...});\n    const latency = Date.now() - start;\n    await logMetrics({\n      model: response.model,\n      latency_ms: latency,\n      input_tokens: response.usage.prompt_tokens,\n      output_tokens: response.usage.completion_tokens,\n      cost: calculateCost(response.usage),\n      timestamp: new Date()\n    });\n    return response;\n  } catch (error) {\n    await logError({ error, prompt_hash: hash(prompt) });\n    throw error;\n  }\n}`,language:'typescript'}],
